const body = $input.first().json.body || $input.first().json;
const project_id = body.project_id;
if (!project_id) throw new Error('project_id required');
return [{ json: { project_id } }];

const project = $('Read Project').first().json[0] || $('Read Project').first().json;
const promptRow = $('Read Prompt Config').first().json[0] || $('Read Prompt Config').first().json;
const project_id = $('Validate').first().json.project_id;

let prompt = promptRow?.prompt_text || '';
prompt = prompt.replace(/\{\{niche\}\}/g, project.niche || '')
  .replace(/\{\{playlist1_name\}\}/g, project.playlist1_name || '')
  .replace(/\{\{playlist1_theme\}\}/g, project.playlist1_theme || '')
  .replace(/\{\{playlist2_name\}\}/g, project.playlist2_name || '')
  .replace(/\{\{playlist2_theme\}\}/g, project.playlist2_theme || '')
  .replace(/\{\{playlist3_name\}\}/g, project.playlist3_name || '')
  .replace(/\{\{playlist3_theme\}\}/g, project.playlist3_theme || '')
  .replace(/\{\{expertise_profile\}\}/g, project.niche_expertise_profile || '')
  .replace(/\{\{blue_ocean_strategy\}\}/g, project.niche_blue_ocean_strategy || '')
  .replace(/\{\{target_video_count\}\}/g, String(project.target_video_count || 25));

if (!prompt) {
  prompt = `Generate ${project.target_video_count || 25} SEO-optimized YouTube topics for the niche "${project.niche}". Return JSON array with topic objects including: topic_number, playlist_group (1-3), playlist_angle, seo_title, narrative_hook, key_segments, estimated_cpm, viral_potential, and nested avatar object with: avatar_name_age, occupation_income, life_stage, pain_point, spending_profile, knowledge_level, emotional_driver, online_hangouts, objection, dream_outcome.`;
}

return [{ json: { project_id, niche: project.niche, prompt } }];

const response = $input.first().json;
if (response.error) throw new Error(`Anthropic error: ${response.error.message}`);
const text = (response.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
let jsonText = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
const s = jsonText.indexOf('['), e = jsonText.lastIndexOf(']');
if (s === -1 || e === -1) throw new Error('No JSON array in response');
const topics = JSON.parse(jsonText.substring(s, e + 1));
const project_id = $('Validate').first().json.project_id;
const topicRows = topics.map((t, i) => ({ project_id, topic_number: t.topic_number || i + 1, playlist_group: t.playlist_group, playlist_angle: t.playlist_angle, original_title: t.seo_title, seo_title: t.seo_title, narrative_hook: t.narrative_hook, key_segments: t.key_segments, estimated_cpm: t.estimated_cpm, viral_potential: t.viral_potential, review_status: 'pending', status: 'pending' }));
const avatarData = topics.map(t => t.avatar || {});
return [{ json: { project_id, topicRows, avatarData } }];

const insertedTopics = $input.first().json;
const topics = Array.isArray(insertedTopics) ? insertedTopics : [insertedTopics];
const avatarData = $('Parse Topics').first().json.avatarData;
const project_id = $('Validate').first().json.project_id;
const avatarRows = topics.map((t, i) => {
  const a = avatarData[i] || {};
  return { topic_id: t.id, project_id, video_title_short: t.seo_title, avatar_name_age: a.avatar_name_age, occupation_income: a.occupation_income, life_stage: a.life_stage, pain_point: a.pain_point, spending_profile: a.spending_profile, knowledge_level: a.knowledge_level, emotional_driver: a.emotional_driver, online_hangouts: a.online_hangouts, objection: a.objection, dream_outcome: a.dream_outcome, review_status: 'pending' };
});
return [{ json: { project_id, avatarRows } }];
